export interface ValidationResult {
    ok: boolean;
    errors: any[];
}

export function validateContext(data: any): ValidationResult {
    return { ok: true, errors: [] };
}

export function validatePlan(data: any): ValidationResult {
    return { ok: true, errors: [] };
}

export function validateConfirm(data: any): ValidationResult {
    return { ok: true, errors: [] };
}

export function validateTrace(data: any): ValidationResult {
    return { ok: true, errors: [] };
}
